import{_ as e,o as l,c as r,a2 as i}from"./chunks/framework.ZhLefgN8.js";const f=JSON.parse('{"title":"基金基础与类型","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/funds/fund-basics.md","filePath":"zh-CN/funds-and-wealth/funds/fund-basics.md"}'),t={name:"funds-and-wealth/funds/fund-basics.md"};function o(h,a,n,d,s,u){return l(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="基金基础与类型" tabindex="-1">基金基础与类型 <a class="header-anchor" href="#基金基础与类型" aria-label="Permalink to &quot;基金基础与类型&quot;">​</a></h1><p>基金定义、各类型基金特征、ETF 和基金分红方式及购买限制。</p><h2 id="什么是基金" tabindex="-1">什么是基金 <a class="header-anchor" href="#什么是基金" aria-label="Permalink to &quot;什么是基金&quot;">​</a></h2><p>基金是一种将多位投资者的资金汇集在一起，由专业基金管理人统一投资管理的资产组合产品。投资者购买基金份额，即按比例持有基金所投资的资产组合，风险和收益由所有份额持有人共同分担和分享。</p><h2 id="基金类型" tabindex="-1">基金类型 <a class="header-anchor" href="#基金类型" aria-label="Permalink to &quot;基金类型&quot;">​</a></h2><h3 id="货币型基金" tabindex="-1">货币型基金 <a class="header-anchor" href="#货币型基金" aria-label="Permalink to &quot;货币型基金&quot;">​</a></h3><p>投资于短期货币市场工具，如国债、央行票据、银行存款等。风险较低，流动性高，收益相对稳定，适合短期资金管理。</p><h3 id="债券型基金" tabindex="-1">债券型基金 <a class="header-anchor" href="#债券型基金" aria-label="Permalink to &quot;债券型基金&quot;">​</a></h3><p>主要投资于债券，包括政府债券、企业债券等固定收益类资产。风险和收益介于货币型和股票型之间，适合追求稳健收益的投资者。</p><h3 id="股票型基金" tabindex="-1">股票型基金 <a class="header-anchor" href="#股票型基金" aria-label="Permalink to &quot;股票型基金&quot;">​</a></h3><p>主要投资于股票市场。收益潜力较高，同时风险也相对较大，适合风险承受能力较强、追求长期资本增值的投资者。</p><h3 id="商品型基金" tabindex="-1">商品型基金 <a class="header-anchor" href="#商品型基金" aria-label="Permalink to &quot;商品型基金&quot;">​</a></h3><p>主要投资于黄金、原油等大宗商品或相关衍生品。可作为资产组合的多元化配置工具，价格受商品市场供需影响。</p><h3 id="平衡型基金" tabindex="-1">平衡型基金 <a class="header-anchor" href="#平衡型基金" aria-label="Permalink to &quot;平衡型基金&quot;">​</a></h3><p>同时投资于股票和债券，通过资产配置平衡风险与收益。适合希望在一定增长潜力和相对稳健之间寻求平衡的投资者。</p><h2 id="什么是-etf" tabindex="-1">什么是 ETF <a class="header-anchor" href="#什么是-etf" aria-label="Permalink to &quot;什么是 ETF&quot;">​</a></h2><p>ETF（交易所交易基金）是一种在证券交易所上市交易的基金，运作方式类似股票。投资者可以像买卖股票一样在交易时间内随时买卖 ETF，买卖价格随市场实时变动。</p><h2 id="交易流程" tabindex="-1">交易流程 <a class="header-anchor" href="#交易流程" aria-label="Permalink to &quot;交易流程&quot;">​</a></h2><h3 id="买入流程" tabindex="-1">买入流程 <a class="header-anchor" href="#买入流程" aria-label="Permalink to &quot;买入流程&quot;">​</a></h3><ol><li>提交买入申请</li><li>等待确认（基金公司按净值确认成交）</li><li>份额到账</li><li>开始计算收益</li></ol><h3 id="卖出流程" tabindex="-1">卖出流程 <a class="header-anchor" href="#卖出流程" aria-label="Permalink to &quot;卖出流程&quot;">​</a></h3><ol><li>提交卖出申请</li><li>等待确认（基金公司按净值确认卖出金额）</li><li>份额扣除</li><li>资金到账</li></ol><h2 id="购买限制" tabindex="-1">购买限制 <a class="header-anchor" href="#购买限制" aria-label="Permalink to &quot;购买限制&quot;">​</a></h2><p>以下情况不支持购买基金：</p><ul><li><strong>待结算资金</strong>：尚未完成结算的资金不可用于购买基金</li><li><strong>跨币种</strong>：不支持使用与基金计价币种不同的资金直接购买</li><li><strong>融资资金</strong>：融资账户资金不可用于购买基金</li></ul><h2 id="分红方式" tabindex="-1">分红方式 <a class="header-anchor" href="#分红方式" aria-label="Permalink to &quot;分红方式&quot;">​</a></h2><p>基金分红统一以份额形式发放。无论账户设置的是现金分红还是再投资，实际均以基金份额的形式分配给投资者。</p><h2 id="收费说明" tabindex="-1">收费说明 <a class="header-anchor" href="#收费说明" aria-label="Permalink to &quot;收费说明&quot;">​</a></h2><p>基金管理费由基金公司收取，已在基金每日净值中扣除。投资者看到的份额单价（单位净值）是扣除管理费后的价格，无需额外支付管理费。</p><h2 id="pi-专区与结构化产品" tabindex="-1">PI 专区与结构化产品 <a class="header-anchor" href="#pi-专区与结构化产品" aria-label="Permalink to &quot;PI 专区与结构化产品&quot;">​</a></h2><p>PI 专区及结构化产品仅向专业投资者（PI）开放。如需访问，请先完成专业投资者认证。认证完成后即可查看和购买相关产品。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/wiki/funds-and-wealth/基金买入与卖出规则">基金买入与卖出规则</a> — 交易操作步骤</li></ul>',33)])])}const b=e(t,[["render",o]]);export{f as __pageData,b as default};
